    expect(getItem(itemId)?.status).toBe('blocked');
  });

  it('transitions bootstrapping → in_progress via bootstrap_ok', () => {
    const wfId = makeWfId();
    const itemId = makeItemId();
    insertWorkflow(wfId);
    insertItem(itemId, wfId, 'stage1', { status: 'bootstrapping' });

