  it('custom retry_ladder is honoured', () => {
    const wfId = makeWfId();
    const itemId = makeItemId();
    insertWorkflow(wfId);
    insertItem(itemId, wfId, 'stage1', { status: 'in_progress', retryCount: 0 });

    const result = applyItemTransition({
