    insertItem(item2, wfId, 'stage1', { status: 'in_progress' });

    const result = applyItemTransition({
      db: pool,
      workflowId: wfId,
      itemId: item2,
      sessionId: null,
      stage: 'stage1',
      phase: 'implement',
      attempt: 1,
      event: 'session_ok',
      guardCtx: { morePhases: false },
